// ═══════════════════════════════════════════════════════
// Step 9: Build Final Synthesis
// Sammelt ALLE Einzelvergleiche und baut den
// finalen LLM-Request fuer die Gesamtgegenueberstellung
// Generisch: Verwendet Config fuer Firmennamen
// ═══════════════════════════════════════════════════════
const allItems = $input.all();
const results = allItems.map(item => item.json);
const config = results[0]?.config || {};

const comparisonSections = results.map(r => {
  return '## ' + r.id + '. ' + r.kategorie + ' - ' + r.aspekt + '\n\n' +
    '**' + config.ownCompanyName + ' (' + config.ownCompanyShort + '):** ' + r.own_data + '\n\n' +
    '**' + config.competitorShort + ' laut RAG-Analyse:**\n' + r.vergleich_aus_rag + '\n\n' +
    '**Benchmark (Excel-Referenz):** ' + r.benchmark_competitor + '\n' +
    '*RAG Chunks: ' + r.ragChunkCount + ' | Distances: ' + (r.ragDistances || []).join(', ') + '*\n';
}).join('\n---\n\n');

const systemPrompt = `Du bist ein Versicherungsexperte der ${config.ownCompanyName}. ` +
  `Du erstellst eine Executive Summary eines AVB-Vergleichs zwischen der ` +
  `${config.ownCompanyName} ${config.ownProductName} und der ${config.competitorName} ${config.competitorProductName}.\n\n` +
  `Die Einzelvergleiche basieren auf einer RAG-Analyse der ${config.competitorShort} AVB-Dokumente. ` +
  'Zusaetzlich ist ein Benchmark-Wert aus einer manuellen Excel-Analyse angegeben.\n\n' +
  '## Aufgabe:\n' +
  'Erstelle basierend auf den Einzelvergleichen eine strukturierte Gegenueberstellung mit:\n\n' +
  `1. **Executive Summary** (3-5 Saetze Gesamtbewertung)\n` +
  `2. **Vorteile ${config.ownCompanyName}** (Bullet-Liste: wo ${config.ownCompanyShort} besser ist, mit konkreten Details)\n` +
  `3. **Vorteile ${config.competitorName}** (Bullet-Liste: wo ${config.competitorShort} besser ist, mit konkreten Details)\n` +
  '4. **Gleichwertige Leistungen** (wo beide aehnlich sind)\n' +
  '5. **Kritische Unterschiede** (die wichtigsten Differenzen fuer die Kundenberatung)\n' +
  `6. **Handlungsempfehlung fuer Produktmanagement** (wo sollte ${config.ownCompanyShort} nachbessern?)\n` +
  '7. **RAG-Qualitaetsbericht** (Vergleiche die RAG-Ergebnisse mit den Benchmark-Werten: ' +
  'Wo stimmen sie ueberein? Wo gibt es Abweichungen? ' +
  'Welche Aspekte konnten nicht aus den AVB ermittelt werden?)\n\n' +
  'Formatiere als Markdown. Sei praezise und faktenbasiert. ' +
  'Unterscheide klar zwischen Fakten aus den AVB und eigenen Bewertungen.';

const userPrompt = 'Hier sind die ' + results.length + ' Einzelvergleiche ' +
  '(jeweils mit RAG-Ergebnis und Excel-Benchmark):\n\n' +
  comparisonSections + '\n\n' +
  'Erstelle bitte die Gesamtgegenueberstellung mit RAG-Qualitaetsbericht.';

return [{
  json: {
    allResults: results,
    resultCount: results.length,
    config: config,
    requestBody: JSON.stringify({
      model: config.llmModel,
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userPrompt }
      ],
      temperature: 0.3,
      max_tokens: 4000,
      stream: false
    })
  }
}];
